  const TABS=[{k:"chat",l:"💬 عمر"},{k:"browse",l:"🏪 المنتجات"},{k:"offers",l:`🏷️${offerProds.length>0?` (${offerProds.length})`:""}`},{k:"loyalty",l:"⭐ نقاطي"},{k:"khayr",l:"🤍 خير"}];

